class BaselTrafficLight:
    def __init__(self, risk_metrics):
        self.risk_metrics = risk_metrics

    def classify_risk(self, var, es, threshold_var=1.0, threshold_es=2.0):
        if var < threshold_var and es < threshold_es:
            return "Green"
        elif var >= threshold_var or es >= threshold_es:
            return "Red"
        else:
            return "Amber"

